+        .stdout
+        .lines()
+        .next()
+        .and_then(|line| {
+            line.strip_prefix("✓ ")
+                .unwrap_or(line)
+                .strip_prefix("Created ")
+                .and_then(|rest| rest.split(':').next())
+        })
+        .expect("parse delete id")
+        .trim()
+        .to_string();
+
+    // Flush so the JSONL shows both issues as open.
