+    assert!(flush.status.success(), "flush failed: {}", flush.stderr);
+
+    // Delete one issue without flushing: tombstone lives only in the DB.
+    let delete_cmd = run_br(
+        &workspace,
+        ["delete", &delete_id, "--force", "--no-auto-flush"],
